// 2. Create Custom Password Validator Annotation
import jakarta.validation.Constraint;
import jakarta.validation.Payload;
import java.lang.annotation.*;

@Documented
@Constraint(validatedBy = StrongPasswordValidator.class)
@Target({ElementType.FIELD, ElementType.PARAMETER})
@Retention(RetentionPolicy.RUNTIME)
public @interface StrongPassword {
    String message() default "Password does not meet security requirements";
    Class<?>[] groups() default {};
    Class<? extends Payload>[] payload() default {};
}

// 3. Implement Validator Logic
import jakarta.validation.ConstraintValidator;
import jakarta.validation.ConstraintValidatorContext;
import org.passay.*;
import java.util.Arrays;
import java.util.List;

public class StrongPasswordValidator implements ConstraintValidator<StrongPassword, String> {

    @Override
    public boolean isValid(String password, ConstraintValidatorContext context) {
        if (password == null || password.isEmpty()) {
            return false;
        }

        PasswordValidator validator = new PasswordValidator(Arrays.asList(
            // Length between 12-128 characters
            new LengthRule(12, 128),

            // At least one uppercase letter
            new CharacterRule(EnglishCharacterData.UpperCase, 1),

            // At least one lowercase letter  
            new CharacterRule(EnglishCharacterData.LowerCase, 1),

            // At least one digit
            new CharacterRule(EnglishCharacterData.Digit, 1),

            // At least one special character
            new CharacterRule(EnglishCharacterData.Special, 1),

            // No whitespace allowed
            new WhitespaceRule(),

            // Check against common passwords dictionary
            new DictionarySubstringRule(
                new WordListDictionary(
                    WordLists.createFromReader(
                        new FileReader[]{new FileReader("common-passwords.txt")}
                    )
                )
            ),

            // No more than 3 consecutive identical characters
            new RepeatCharacterRegexRule(3)
        ));

        RuleResult result = validator.validate(new PasswordData(password));

        if (!result.isValid()) {
            context.disableDefaultConstraintViolation();
            context.buildConstraintViolationWithTemplate(
                String.join(", ", validator.getMessages(result))
            ).addConstraintViolation();
            return false;
        }

        return true;
    }
}

