const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // Limit each IP to 5 requests per windowMs
  message: 'Too many authentication attempts, please try again after 15 minutes',
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    res.status(429).json({
      error: 'Too many requests',
      message: 'Authentication rate limit exceeded',
      retryAfter: req.rateLimit.resetTime
    });
  }
});

// 4. Custom password validation middleware
const validatePassword = (password, userInputs = []) => {
  const errors = [];

  // Check minimum length
  if (password.length < 12) {
    errors.push('Password must be at least 12 characters long');
  }

  // Check maximum length
  if (password.length > 128) {
    errors.push('Password must not exceed 128 characters');
  }

  // Check complexity requirements
  if (!/[a-z]/.test(password)) {
    errors.push('Password must contain at least one lowercase letter');
  }
  if (!/[A-Z]/.test(password)) {
    errors.push('Password must contain at least one uppercase letter');
  }
  if (!/[0-9]/.test(password)) {
    errors.push('Password must contain at least one number');
  }
  if (!/[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password)) {
    errors.push('Password must contain at least one special character');
  }

  // Check for whitespace
  if (/\s/.test(password)) {
    errors.push('Password must not contain whitespace');
  }

  // Check for common patterns
  if (/12345|qwerty|password|admin|letmein/i.test(password)) {
    errors.push('Password contains common patterns and is not allowed');
  }

  // Use zxcvbn for strength estimation (0-4 score)
  const result = zxcvbn(password, userInputs);
  if (result.score < 3) {
    errors.push(
      `Password is too weak (strength: ${result.score}/4). ` +
      `Suggestion: ${result.feedback.suggestions.join(', ') || 'Use a longer, more complex password'}`
    );
  }

  return {
    isValid: errors.length === 0,
    errors: errors,
    strength: result.score,
    feedback: result.feedback
  };
};

