    body('email')
      .isEmail()
      .normalizeEmail()
      .withMessage('Invalid email address'),
    body('password')
      .custom((password, { req }) => {
        // Pass email and username as user inputs to zxcvbn
        const userInputs = [req.body.email, req.body.username].filter(Boolean);
        const validation = validatePassword(password, userInputs);

        if (!validation.isValid) {
          throw new Error(validation.errors.join('; '));
