from django.core.exceptions import ValidationError
from django.utils.translation import gettext as _
import re
import hashlib
import requests


class ComplexityValidator:
    """
    Validates password complexity requirements:
    - At least one uppercase letter
    - At least one lowercase letter  
    - At least one digit
    - At least one special character
    - No whitespace allowed
    """

    def __init__(self):
        self.special_chars = r"!@#$%^&*()_+-=[]{}|;:',.<>?/~`"

    def validate(self, password, user=None):
        errors = []

        if not re.search(r'[a-z]', password):
            errors.append(_('Password must contain at least one lowercase letter.'))

        if not re.search(r'[A-Z]', password):
            errors.append(_('Password must contain at least one uppercase letter.'))

        if not re.search(r'[0-9]', password):
            errors.append(_('Password must contain at least one digit.'))

        if not re.search(r'[!@#$%^&*()_+\-=\[\]{}|;:\',.<>?/~`]', password):
            errors.append(_('Password must contain at least one special character.'))

        if re.search(r'\s', password):
            errors.append(_('Password must not contain whitespace.'))

        # Check for repeated characters (more than 3 consecutive)
        if re.search(r'(.)\1{3,}', password):
            errors.append(_('Password contains too many repeated characters.'))

        if errors:
            raise ValidationError(errors)

    def get_help_text(self):
        return _(
            "Your password must contain at least one uppercase letter, "
            "one lowercase letter, one digit, and one special character. "
            "Whitespace and excessive repeated characters are not allowed."
        )


class CompromisedPasswordValidator:
    """
    Validates password against HaveIBeenPwned database using k-anonymity.
    Uses the first 5 characters of the SHA-1 hash to query the API.
    """

    def __init__(self, threshold=1):
        self.threshold = threshold  # Minimum number of times seen in breaches

    def validate(self, password, user=None):
        # Hash the password
        sha1_hash = hashlib.sha1(password.encode('utf-8')).hexdigest().upper()
        prefix = sha1_hash[:5]
        suffix = sha1_hash[5:]

        try:
            # Query HaveIBeenPwned API (k-anonymity)
            response = requests.get(
                f'https://api.pwnedpasswords.com/range/{prefix}',
                timeout=2,
                headers={'Add-Padding': 'true'}  # Prevent response size analysis
            )

            if response.status_code == 200:
                # Check if our hash suffix appears in response
                hashes = (line.split(':') for line in response.text.splitlines())
                for hash_suffix, count in hashes:
                    if hash_suffix == suffix:
                        count = int(count)
                        if count >= self.threshold:
                            raise ValidationError(
                                _('This password has been compromised in %(count)d data breaches '
                                  'and cannot be used.'),
                                code='password_compromised',
                                params={'count': count}
                            )
        except requests.exceptions.RequestException:
            # If API is unavailable, log but don't block password change
            import logging
            logging.warning('HaveIBeenPwned API unavailable, skipping compromised password check')

    def get_help_text(self):
        return _(
            "Your password will be checked against known compromised passwords. "
            "Passwords found in data breaches cannot be used."
        )


# 4. Create registration view with validation
# accounts/views.py

from django.contrib.auth import authenticate, login
from django.contrib.auth.models import User
from django.contrib.auth.password_validation import validate_password
from django.core.exceptions import ValidationError
from django.http import JsonResponse
from django.views.decorators.csrf import csrf_protect
from django.views.decorators.http import require_http_methods
import json


@csrf_protect
@require_http_methods(["POST"])
def register_user(request):
    """
    User registration endpoint with password validation.
    """
    try:
        data = json.loads(request.body)
        email = data.get('email', '').strip()
        password = data.get('password', '')

        # Validate email
        if not email or '@' not in email:
            return JsonResponse(
                {'error': 'Invalid email address'},
                status=400
            )

        # Check if user already exists
        if User.objects.filter(email=email).exists():
            return JsonResponse(
                {'error': 'Email already registered'},
                status=400
            )

        # Create temporary user for validation
        temp_user = User(email=email, username=email.split('@')[0])

        # Validate password against all configured validators
        try:
            validate_password(password, user=temp_user)
        except ValidationError as e:
            return JsonResponse(
                {'error': 'Password validation failed', 'details': e.messages},
                status=400
            )

        # Create user (password is automatically hashed by Django)
        user = User.objects.create_user(
            username=temp_user.username,
            email=email,
            password=password
        )

        # Log the user in
        login(request, user)

        return JsonResponse({
            'message': 'Registration successful',
            'user_id': user.id,
            'email': user.email
        }, status=201)

    except json.JSONDecodeError:
        return JsonResponse({'error': 'Invalid JSON'}, status=400)
    except Exception as e:
        return JsonResponse({'error': str(e)}, status=500)


@csrf_protect
@require_http_methods(["POST"])
def login_user(request):
    """
    User login endpoint (protected by django-axes).
    """
    try:
        data = json.loads(request.body)
        email = data.get('email', '').strip()
        password = data.get('password', '')

        # Authenticate user
        user = authenticate(request, username=email, password=password)

        if user is not None:
            login(request, user)
            return JsonResponse({
                'message': 'Login successful',
                'user_id': user.id
            })
        else:
            # Generic error message to prevent user enumeration
            return JsonResponse(
                {'error': 'Invalid credentials'},
                status=401
            )

    except json.JSONDecodeError:
        return JsonResponse({'error': 'Invalid JSON'}, status=400)
    except Exception as e:
        return JsonResponse({'error': str(e)}, status=500)


